import ScrollListener from '../shared/scroll-listener.js';const BackToTop={button: null,scrollThreshold: 300,isVisible: false,init(){this.createButton();this.bindScroll();this.bindClick();},createButton(){if(document.getElementById('back-to-top'))return;this.button=document.createElement('button');this.button.id='back-to-top';this.button.className='back-to-top';this.button.setAttribute('aria-label','Back to top');this.button.innerHTML=`<span class="material-symbols-outlined">keyboard_arrow_up</span>`;document.body.appendChild(this.button);},bindScroll(){const onScroll=()=>{const shouldShow=window.scrollY>this.scrollThreshold;if(shouldShow&&!this.isVisible){this.show();}else if(!shouldShow&&this.isVisible){this.hide();}};ScrollListener.add('back-to-top',onScroll,{passive: true,debounce: 50});onScroll();},bindClick(){if(!this.button)return;this.button.addEventListener('click',()=>{this.scrollToTop();});this.button.addEventListener('keydown',(e)=>{if(e.key==='Enter'||e.key===' '){e.preventDefault();this.scrollToTop();}});},show(){if(!this.button)return;this.button.classList.add('visible');this.button.setAttribute('aria-hidden','false');this.isVisible=true;},hide(){if(!this.button)return;this.button.classList.remove('visible');this.button.setAttribute('aria-hidden','true');this.isVisible=false;},scrollToTop(){window.scrollTo({top: 0,behavior: 'smooth'});this.button.focus();},destroy(){if(this.button){this.button.remove();this.button=null;}}};if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>BackToTop.init());}else{BackToTop.init();}export{BackToTop};